import { describe, expect, it } from '@a0n/gnosis/test';
import { BettyCompiler } from './betty/compiler';
import {
  graphAstToIotaTree,
  iotaApp,
  iotaLeaf,
  iotaTreeApplicationCount,
  iotaTreeLeafCount,
  iotaTreeToGg,
  iotaTreeToTopology,
  leftSpineThreeIotaTree,
} from './iota-trees';
import {
  PROTOCOL69_IOTA_PROGRAM_CACHE_KEY_PREFIX,
  buildProtocol69IotaProgramTeleportEnvelope,
  runProtocol69IotaProgramTeleport,
  validateProtocol69IotaProgramTeleportEnvelope,
} from './protocol69';
import type { GraphAST } from './betty/compiler';

function requireAst(ast: GraphAST | null): GraphAST {
  if (!ast) throw new Error('expected Betty to parse an iota topology');
  return ast;
}

describe('iota tree topology bridge', () => {
  it('renders unlabeled binary iota trees as GG topology', () => {
    const topology = iotaTreeToTopology(leftSpineThreeIotaTree);

    expect(topology.rootId).toBe('iota_root');
    expect(topology.nodes).toHaveLength(5);
    expect(topology.edges).toHaveLength(4);
    expect(iotaTreeLeafCount(leftSpineThreeIotaTree)).toBe(3);
    expect(iotaTreeApplicationCount(leftSpineThreeIotaTree)).toBe(2);

    const gg = iotaTreeToGg(leftSpineThreeIotaTree);
    expect(gg).toContain('(iota_root:IotaApp');
    expect(gg).toContain('(iota_root_L:IotaApp');
    expect(gg).toContain('(iota_root_R:IotaLeaf');
    expect(gg).toContain("[:ROOT { role: 'iota-root' }]");
    expect(gg).toContain("[:LEFT { role: 'iota-left' }]");
    expect(gg).toContain("[:RIGHT { role: 'iota-right' }]");
  });

  it('round-trips through Betty GraphAST without losing tree shape', () => {
    const tree = iotaApp(iotaLeaf, iotaApp(iotaLeaf, iotaLeaf));
    const gg = iotaTreeToGg(tree);
    const parsed = new BettyCompiler().parse(gg);

    expect(
      parsed.diagnostics.filter((diagnostic) => diagnostic.severity === 'error')
    ).toEqual([]);
    expect(parsed.ast?.nodes.size).toBe(6);
    expect(parsed.ast?.edges).toHaveLength(5);
    const ast = requireAst(parsed.ast);

    const recovered = graphAstToIotaTree(ast);
    expect(recovered).toEqual(tree);
  });

  it('rejects non-bijective app nodes with missing children', () => {
    const parsed = new BettyCompiler().parse(`
      (iota_root:IotaApp { kind: 'app', path: 'root' })
      (iota_root_L:IotaLeaf { kind: 'leaf', path: 'root.L' })
      (iota_root)-[:LEFT { role: 'iota-left' }]->(iota_root_L)
    `);

    const ast = requireAst(parsed.ast);
    expect(() => graphAstToIotaTree(ast)).toThrow(
      "must have exactly one right edge"
    );
  });

  it('rejects cyclic iota topology even if GG parses it', () => {
    const parsed = new BettyCompiler().parse(`
      (iota_root:IotaApp { kind: 'app', path: 'root' })
      (iota_leaf:IotaLeaf { kind: 'leaf', path: 'root.R' })
      (iota_root)-[:LEFT { role: 'iota-left' }]->(iota_root)
      (iota_root)-[:RIGHT { role: 'iota-right' }]->(iota_leaf)
    `);

    const ast = requireAst(parsed.ast);
    expect(() => graphAstToIotaTree(ast)).toThrow("contains a cycle");
  });

  it('rejects leaves with hidden iota children', () => {
    const parsed = new BettyCompiler().parse(`
      (iota_root:IotaLeaf { kind: 'leaf', path: 'root' })
      (iota_child:IotaLeaf { kind: 'leaf', path: 'root.L' })
      (iota_root)-[:LEFT { role: 'iota-left' }]->(iota_child)
    `);

    const ast = requireAst(parsed.ast);
    expect(() => graphAstToIotaTree(ast)).toThrow('must have no iota children');
  });

  it('inflates protocol69 in-room app teleport to a compute cache key', () => {
    const session = {
      transport: 'in-room-rf',
      radio: 'pluto-sdr',
      antennaCount: 2,
      roomId: 'lab',
      attenuationDb: 30,
    } as const;
    const envelope = buildProtocol69IotaProgramTeleportEnvelope(
      leftSpineThreeIotaTree,
      session
    );

    expect(envelope.session).toEqual(session);
    expect(envelope.leafCount).toBe(3);
    expect(envelope.applicationCount).toBe(2);
    expect(envelope.keyMaterial).toMatchObject({
      sourceNodeCount: 5,
      ggNodeCount: 6,
      ggEdgeCount: 5,
      projectionOperand: 69,
      localOperand: 7,
      programChecksum: envelope.programChecksum,
    });
    expect(envelope.computeCacheKey).toMatch(
      new RegExp(`^${PROTOCOL69_IOTA_PROGRAM_CACHE_KEY_PREFIX}:`)
    );
    expect(validateProtocol69IotaProgramTeleportEnvelope(envelope)).toBe(
      envelope
    );

    const receipt = runProtocol69IotaProgramTeleport(
      leftSpineThreeIotaTree,
      session
    );
    expect(receipt.teleportKind).toBe('iota-program-cache-key');
    expect(receipt.computeCacheKey).toBe(envelope.computeCacheKey);
    expect(receipt.ggNodeCount).toBe(6);
    expect(receipt.ggEdgeCount).toBe(5);
    expect(receipt.keyMaterial).toEqual(envelope.keyMaterial);
    expect(receipt.nodeCount).toBe(5);
  });

  it('rejects tampered protocol69 iota cache keys', () => {
    const envelope = buildProtocol69IotaProgramTeleportEnvelope(
      leftSpineThreeIotaTree
    );

    expect(() =>
      validateProtocol69IotaProgramTeleportEnvelope({
        ...envelope,
        computeCacheKey: `${PROTOCOL69_IOTA_PROGRAM_CACHE_KEY_PREFIX}:00000000`,
      })
    ).toThrow('compute cache key mismatch');
  });

  it('rejects tampered protocol69 iota key material', () => {
    const envelope = buildProtocol69IotaProgramTeleportEnvelope(
      leftSpineThreeIotaTree
    );

    expect(() =>
      validateProtocol69IotaProgramTeleportEnvelope({
        ...envelope,
        keyMaterial: {
          ...envelope.keyMaterial,
          ggEdgeCount: envelope.keyMaterial.ggEdgeCount + 1,
        },
      })
    ).toThrow('key material mismatch');
  });
});
